  "steps": [
    {
      "order": 1,
      "title": "오징어 상태 확인",
      "description": [
        {
          "content": "비닐봉지에서 오징어를 꺼내 확인해주세요.",
          "start": "00:00:05",
          "end": "00:00:11"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 2,
      "title": "오징어 세척 및 기본 손질",
      "description": [
        {
          "content": "오징어를 흐르는 물에 깨끗이 씻어주세요.",
          "start": "00:01:34",
          "end": "00:01:37"
        },
        {
          "content": "오징어 다리를 잡아당겨 몸통과 분리해주세요.",
          "start": "00:01:38",
          "end": "00:01:41"
        },
        {
          "content": "오징어 몸통 내부의 뼈를 제거해주세요.",
          "start": "00:01:42",
          "end": "00:01:47"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "label": "몸통과 분리",
          "start": "00:01:38",
          "end": "00:01:41"
        },
        {
          "label": "뼈를 제거",
          "start": "00:01:42",
          "end": "00:01:47"
        }
      ]
    },
    {
      "order": 3,
      "title": "오징어 다리 손질",
      "description": [
        {
          "content": "오징어 다리를 손으로 훑으며 이물질을 세척해주세요.",
          "start": "00:01:50",
          "end": "00:01:53"
        },
        {
          "content": "오징어 다리 빨판에 붙은 이물질을 손톱으로 긁어 제거해주세요.",
          "start": "00:01:54",
          "end": "00:02:01"
        },
        {
          "content": "세척한 오징어를 물에 두 번 정도 헹궈주세요.",
          "start": "00:02:02",
          "end": "00:02:06"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 4,
      "title": "오징어 몸통 칼집 내기",
      "description": [
        {
          "content": "오징어 몸통을 뒤집어 안쪽 살에 칼집을 낼 준비를 하세요.",
          "start": "00:02:29",
          "end": "00:02:31"
        },
        {
          "content": "칼집을 내기 쉽도록 오징어 몸통을 세로로 반 갈라주세요.",
          "start": "00:02:32",
          "end": "00:02:34"
        },
        {
          "content": "오징어 몸통에 세로 방향으로 촘촘하게 칼집을 넣어주세요.",
          "start": "00:02:35",
          "end": "00:02:43"
        },
        {
          "content": "격자 모양이 되도록 대각선 방향으로 다시 칼집을 넣어주세요.",
          "start": "00:02:44",
          "end": "00:02:49"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "label": "세로로 반 갈라주세요",
          "start": "00:02:32",
          "end": "00:02:34"
        },
        {
          "label": "세로 방향으로 칼집",
          "start": "00:02:35",
          "end": "00:02:43"
        },
        {
          "label": "대각선 방향으로 칼집",
          "start": "00:02:44",
          "end": "00:02:49"
        }
      ]
    },
    {
      "order": 5,
      "title": "손질한 오징어 썰기",
      "description": [
        {
          "content": "칼집을 넣은 오징어 몸통을 한입 크기로 작게 썰어주세요.",
          "start": "00:03:04",
          "end": "00:03:10"
        },
        {
          "content": "오징어 다리 사이에 있는 이빨을 손으로 눌러 제거해주세요.",
          "start": "00:03:10",
          "end": "00:03:16"
        },
        {
          "content": "오징어 다리를 먹기 좋은 크기로 숭덩숭덩 썰어주세요.",
          "start": "00:03:17",
          "end": "00:03:23"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "label": "이빨을 제거해주세요",
          "start": "00:03:10",
          "end": "00:03:16"
        }
      ]
    },
    {
      "order": 6,
      "title": "채소 손질하기",
      "description": [
        {
          "content": "양파 1개를 채 썰어주세요.",
          "start": "00:03:30",
          "end": "00:03:31"
        },
        {
          "content": "대파 1대를 어긋썰기 하여 준비해주세요.",
          "start": "00:03:32",
          "end": "00:03:34"
        },
        {
          "content": "통마늘 약 10알을 준비해주세요.",
          "start": "00:03:35",
          "end": "00:03:40"
        },
        {
          "content": "마늘을 너무 얇지 않게 편으로 썰어주세요.",
          "start": "00:03:41",
          "end": "00:03:45"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 7,
      "title": "청양고추 손질하기",
      "description": [
        {
          "content": "청양고추 3개를 송송 썰어주세요.",
          "start": "00:03:55",
          "end": "00:04:00"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 8,
      "title": "팬 예열 및 기름 두르기",
      "description": [
        {
          "content": "프라이팬을 강불에서 예열해주세요.",
          "start": "00:04:57",
          "end": "00:04:59"
        },
        {
          "content": "팬에 식용유를 4바퀴 정도 넉넉하게 둘러주세요.",
          "start": "00:05:00",
          "end": "00:05:10"
        },
        {
          "content": "기름에 참기름 1큰술을 추가하여 풍미를 더해주세요.",
          "start": "00:05:19",
          "end": "00:05:25"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 9,
      "title": "향신채 볶아 향 내기",
      "description": [
        {
          "content": "예열된 팬에 썰어둔 대파를 넣고 강불에서 볶아주세요.",
          "start": "00:05:27",
          "end": "00:05:34"
        },
        {
          "content": "대파 다음으로 편마늘을 넣고 함께 볶아 향을 내주세요.",
          "start": "00:05:42",
          "end": "00:05:46"
        },
        {
          "content": "청양고추를 넣고 함께 볶아주세요.",
          "start": "00:05:51",
          "end": "00:05:58"
        },
        {
          "content": "재료들의 색이 살짝 변하기 시작하면 불을 약불로 줄여주세요.",
          "start": "00:06:01",
          "end": "00:06:07"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "label": "색이 살짝 변하기 시작하면",
          "start": "00:06:01",
          "end": "00:06:07"
        }
      ]
    },
    {
      "order": 10,
      "title": "고추기름 양념 만들기",
      "description": [
        {
          "content": "고춧가루 3큰술을 넣어주세요.",
          "start": "00:06:34",
          "end": "00:06:39"
        },
        {
          "content": "약불에서 2~3분간 충분히 볶아 고추기름을 내주세요.",
          "start": "00:06:40",
          "end": "00:06:51"
        }
      ],
      "timerSeconds": 150,
      "scenes": [
        {
          "label": "고추기름을 내주세요",
          "start": "00:06:40",
          "end": "00:06:51"
        }
      ]
    },
    {
      "order": 11,
      "title": "설탕 넣어 볶기",
      "description": [
        {
          "content": "고추기름에 설탕 3큰술을 넣어주세요.",
          "start": "00:06:52",
          "end": "00:06:57"
        },
        {
          "content": "약불을 유지하며 2~3분 정도 더 볶아주세요.",
          "start": "00:07:05",
          "end": "00:07:13"
        }
      ],
      "timerSeconds": 150,
      "scenes": []
    },
    {
      "order": 12,
      "title": "간장과 고추장으로 양념 완성하기",
      "description": [
        {
          "content": "양조간장 4큰술을 팬의 한쪽에 부어 넣어주세요.",
          "start": "00:07:30",
          "end": "00:07:34"
        },
        {
          "content": "간장을 넣은 후 불을 다시 강불로 올려주세요.",
          "start": "00:07:36",
          "end": "00:07:39"
        },
        {
          "content": "간장을 보글보글 끓여 산미를 날리고 풍미를 더해주세요.",
          "start": "00:07:40",
          "end": "00:07:46"
        },
        {
          "content": "고추장 1큰술을 넣어주세요.",
          "start": "00:07:47",
          "end": "00:07:52"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "label": "간장을 보글보글 끓여",
          "start": "00:07:40",
          "end": "00:07:46"
        }
      ]
    },
    {
      "order": 13,
      "title": "양파와 오징어 넣고 볶기",
      "description": [
        {
          "content": "채 썬 양파를 넣어주세요.",
          "start": "00:07:53",
          "end": "00:07:56"
        },
        {
          "content": "양념과 양파가 잘 어우러지도록 고루 섞으며 볶아주세요.",
          "start": "00:07:57",
          "end": "00:08:08"
        },
        {
          "content": "준비한 오징어를 모두 넣어주세요.",
          "start": "00:08:10",
          "end": "00:08:16"
        },
        {
          "content": "오징어가 붉은 양념과 잘 섞이도록 빠르게 볶아주세요.",
          "start": "00:08:17",
          "end": "00:08:26"
        }
      ],
      "timerSeconds": null,
      "scenes": []
    },
    {
      "order": 14,
      "title": "오징어 익히고 수분 날리기",
      "description": [
        {
          "content": "중불로 조정한 뒤 뚜껑을 덮고 2분간 쪄내듯 익혀주세요.",
          "start": "00:08:34",
          "end": "00:08:43"
        },
        {
          "content": "2분 후 뚜껑을 열고 수분을 확인해주세요.",
          "start": "00:08:44",
          "end": "00:08:51"
        },
        {
          "content": "다시 강불로 올려 화력을 조절해주세요.",
          "start": "00:08:52",
          "end": "00:08:55"
        },
        {
          "content": "강불에서 볶으며 수분을 날리고 불맛을 입혀주세요.",
          "start": "00:08:56",
          "end": "00:09:01"
        }
      ],
      "timerSeconds": 120,
      "scenes": []
    },
    {
      "order": 15,
      "title": "불맛 입히고 마무리하기",
      "description": [
        {
          "content": "뒤적거리지 않고 그대로 두어 양념이 팬 바닥에 살짝 눌어붙게 하세요.",
          "start": "00:09:10",
          "end": "00:09:15"
        },
        {
          "content": "눌어붙은 양념을 긁어가며 오징어와 함께 골고루 섞어주세요.",
          "start": "00:09:27",
          "end": "00:09:34"
        },
        {
          "content": "가스레인지의 불을 꺼주세요.",
          "start": "00:09:35",
          "end": "00:09:39"
        },
        {
          "content": "통깨를 솔솔 뿌려 요리를 마무리하세요.",
          "start": "00:09:45",
          "end": "00:09:50"
        }
      ],
      "timerSeconds": null,
      "scenes": [
        {
          "label": "살짝 눌어붙게 하세요",
          "start": "00:09:10",
          "end": "00:09:15"
        },
        {
          "label": "눌어붙은 양념을 긁어가며",
          "start": "00:09:27",
          "end": "00:09:34"
        }
      ]
    }
  ],
  "servingTip": "안주용으로는 큼직하게, 밥과 면용으로는 작게 썰어서 조리하는 것을 추천함"
}
